const deduplicateData = $('Deduplicate Check').item.json;
const website = deduplicateData.website || '';
const email = deduplicateData.email || '';
const instagramHandle = deduplicateData.instagramHandle || '';
const placeId = deduplicateData.placeId || '';
const placeName = deduplicateData.placeName || '';

function extractDomain(url) {
  if (!url) return '';
  try {
    let domain = url.replace(/^https?:\/\//, '').replace(/^www\./, '');
    domain = domain.split('/')[0].toLowerCase();
    return domain;
  } catch (e) { return ''; }
}

function extractEmailDomain(email) {
  if (!email || !email.includes('@')) return '';
  return email.split('@')[1].toLowerCase();
}

// Website domain blacklist (social/booking platforms)
const websiteBlacklist = ['facebook.com', 'instagram.com', 'chope.co', 'quandoo.com', 'fb.com', 'm.facebook.com', 'chope.com.sg'];

// Email domain blacklist (social/booking + B2C email providers)
const emailBlacklist = [
  // Social/booking platforms
  'facebook.com', 'instagram.com',
  // B2C email providers
  'gmail.com', 'yahoo.com', 'outlook.com', 'hotmail.com', 'live.com', 'msn.com',
  'icloud.com', 'me.com', 'mac.com', 'aol.com', 'protonmail.com', 'proton.me',
  'ymail.com', 'rocketmail.com', 'mail.com', 'zoho.com', 'gmx.com', 'gmx.net'
];

function isWebsiteBlacklisted(domain) {
  if (!domain) return true;
  return websiteBlacklist.some(bl => domain === bl || domain.endsWith('.' + bl));
}

function isEmailBlacklisted(domain) {
  if (!domain) return true;
  return emailBlacklist.some(bl => domain === bl || domain.endsWith('.' + bl));
}

const websiteDomain = extractDomain(website);
const emailDomain = extractEmailDomain(email);

// Get personRecordId from the Set Person ID node (passed via Merge)
const personRecordId = $json.personRecordId || '';

return [{
  json: {
    websiteDomain: isWebsiteBlacklisted(websiteDomain) ? '' : websiteDomain,
    emailDomain: isEmailBlacklisted(emailDomain) ? '' : emailDomain,
    instagramHandle: instagramHandle.replace('@', ''),
    placeId,
    placeName,
    country: deduplicateData.country || '',
    cuisine: deduplicateData.cuisine || '',
    personRecordId
  }
}];

const preparedData = $('Prepare Company Search').item.json;

let companyFound = null;
let foundByMethod = null;

const searchNodes = [
  { name: 'websiteDomain', node: 'Search Company by Website Domain' },
  { name: 'emailDomain', node: 'Search Company by Email Domain' },
  { name: 'instagram', node: 'Search Company by Instagram' },
  { name: 'placeId', node: 'Search Company by PlaceId' },
  { name: 'placeName', node: 'Search Company by PlaceName' }
];

for (const search of searchNodes) {
  try {
    const result = $(search.node).item.json;
    if (result?.data?.length > 0) {
      companyFound = result.data[0];
      foundByMethod = search.name;
      break;
    }
  } catch (e) {}
}

return [{
  json: {
    companyFound: !!companyFound,
    companyRecordId: companyFound?.id?.record_id || '',
    foundByMethod,
    needsInstagramUpdate: companyFound && foundByMethod !== 'instagram' && preparedData.instagramHandle,
    ...preparedData
  }
}];

// Email Existing Path: Person was found by email search
const personRecordId = $('Search Attio Person by Email').item.json.data[0].id.record_id;

return [{
  json: {
    personRecordId,
    listEntryData: $json
  }
}];

// Email New Path: Person was just created
const personRecordId = $('Create New Person (Email Path)').item.json.data.id.record_id;

return [{
  json: {
    personRecordId,
    listEntryData: $json
  }
}];

// Phone Existing Path: Person was found by phone search
const personRecordId = $('Search Attio Person by Phone').item.json.data[0].id.record_id;

return [{
  json: {
    personRecordId,
    listEntryData: $json
  }
}];

// Phone New Path: Person was just created
const personRecordId = $('Create New Person (Phone Path)').item.json.data.id.record_id;

return [{
  json: {
    personRecordId,
    listEntryData: $json
  }
}];
